#include<iostream>
using namespace std;
int n;
int pos[15];     // pos[row] = col
bool col[15], diag1[30], diag2[30];

void dfs(int row){
    if(row == n+1){
        for(int i=1; i<=n; i++) cout << pos[i];
        cout << endl;
        return;
    }
