    bool first = true;
    for(int i=15; i>=0; i--){
        if(n & (1<<i)){
            if(!first) cout << "+";
            first = false;
            if(i == 0) cout << "2(0)";
            else if(i == 1) cout << "2";
            else {
                cout << "2(";
                solve(i);
                cout << ")";
