LinK22:
本题计算仅有+和*的算术表达式，关键是要对结果取模1000000007。
由于只有+和*两种运算，不用考虑优先级栈。乘法优先级高于加法，所以每读一个数字就累积乘法结果，遇到+号就把乘法结果加到总和中。
⚠️注意：中间结果可能溢出，要全程取模。
源码：
#include<iostream>
#include<string>
using namespace std;

const int MOD = 1000000007;

int main(){
    int n;
    string s;
    cin >> n >> s;
    long long ans = 0;
    long long mul = 0;  // 当前乘法累积值
    for(char c : s){
        if(c >= '1' && c <= '9'){
            mul = (mul * 10 + (c - '0')) % MOD;  // 这个不会出现，因为数字都是1-9单数
            mul = c - '0';
        }
    }
    // 重新解析
    ans = 0;
    mul = s[0] - '0';
    for(int i=1; i<(int)s.size(); i+=2){
        char op = s[i];
        int num = s[i+1] - '0';
        if(op == '*'){
            mul = (mul * num) % MOD;
        } else {  // '+'
            ans = (ans + mul) % MOD;
            mul = num;
        }
    }
    ans = (ans + mul) % MOD;
    cout << ans << endl;
    return 0;
}

LinK23:
本题是二进制密码锁，本质上是一个贪心+枚举问题。
由于按一个按钮会影响相邻按钮，思路是：从左到右处理，如果当前位置与目标不同，就按下一个位置的按钮（这样当前位就被修正，且不影响左边已处理好的）。
但第一个按钮的状态不确定（按或不按），所以要枚举两种情况。
源码：
#include<iostream>
#include<string>
#include<algorithm>
using namespace std;

const int INF = 1e9;
string s, t;
int n;

int solve(bool pressFirst){
    string a = s;
    int cnt = 0;
    if(pressFirst){
        a[0] ^= 1;
        if(n > 1) a[1] ^= 1;
        cnt++;
    }
    for(int i=1; i<n; i++){
        if(a[i-1] != t[i-1]){
            a[i-1] ^= 1;
            a[i] ^= 1;
            if(i+1 < n) a[i+1] ^= 1;
            cnt++;
        }
    }
    if(a == t) return cnt;
    return INF;
}

int main(){
    cin >> s >> t;
    n = s.size();
    int ans = min(solve(false), solve(true));
    if(ans == INF) cout << "impossible" << endl;
    else cout << ans << endl;
    return 0;
}

