    memcpy(tmp, light, sizeof(light));
    for(int i=0; i<5; i++){
        for(int j=0; j<6; j++){
            if(press[i][j]){
                tmp[i][j] ^= 1;
                if(i>0) tmp[i-1][j] ^= 1;
                if(i<4) tmp[i+1][j] ^= 1;
                if(j>0) tmp[i][j-1] ^= 1;
                if(j<5) tmp[i][j+1] ^= 1;
            }
        }
        if(i < 4){
            for(int j=0; j<6; j++)
                press[i+1][j] = tmp[i][j];
        }
    }
    for(int j=0; j<6; j++)
        if(tmp[4][j]) return false;
    return true;
}

int main(){
    int T;
    cin >> T;
    for(int t=1; t<=T; t++){
        for(int i=0; i<5; i++)
            for(int j=0; j<6; j++)
                cin >> light[i][j];
        // 枚举第一行
        for(int mask=0; mask<(1<<6); mask++){
            memset(press, 0, sizeof(press));
            for(int j=0; j<6; j++)
                press[0][j] = (mask>>j) & 1;
            if(check()) break;
        }
        cout << "PUZZLE #" << t << endl;
        for(int i=0; i<5; i++){
            for(int j=0; j<6; j++){
                cout << press[i][j];
