}

LinK26:
本题是算24点问题。用DFS枚举所有运算组合。
递归思路：从4个数中任选两个，进行加减乘除六种运算（a+b, a-b, b-a, a*b, a/b, b/a），
得到一个新数替换选中的两个数，问题缩小为3个数算24。递归到只剩1个数时判断是否为24。
⚠️除法要判断除数不为0（或接近0）。
源码：
#include<iostream>
#include<cmath>
using namespace std;

double a[4];
const double EPS = 1e-6;

bool dfs(int n){
    if(n == 1) return fabs(a[0]-24) < EPS;
    for(int i=0; i<n; i++){
        for(int j=i+1; j<n; j++){
            double x = a[i], y = a[j];
            double b[4]; int m=0;
            for(int k=0; k<n; k++)
                if(k!=i && k!=j) b[m++] = a[k];
            // 六种运算
            double ops[] = {x+y, x-y, y-x, x*y};
            for(int k=0; k<4; k++){
                b[m] = ops[k];
                for(int t=0; t<=m; t++) a[t] = b[t];
                if(dfs(n-1)) return true;
            }
            if(fabs(y)>EPS) { b[m]=x/y; for(int t=0; t<=m; t++) a[t]=b[t]; if(dfs(n-1)) return true; }
            if(fabs(x)>EPS) { b[m]=y/x; for(int t=0; t<=m; t++) a[t]=b[t]; if(dfs(n-1)) return true; }
        }
    }
    return false;
}

int main(){
    while(cin>>a[0]>>a[1]>>a[2]>>a[3]){
        if(a[0]==0 && a[1]==0 && a[2]==0 && a[3]==0) break;
        cout << (dfs(4) ? "YES" : "NO") << endl;
    }
    return 0;
}

