LinK28:
快速选择第k小的数，用类似快排的partition思想。
每次选pivot，partition后左边都小于等于pivot，右边都大于pivot。
如果左边个数>=k，答案在左边，递归左边；否则答案在右边，k减去左边个数继续递归。
平均O(n)。
源码：
#include<iostream>
using namespace std;

int a[100005];

int quickSelect(int l, int r, int k){
    if(l == r) return a[l];
    int pivot = a[(l+r)/2];
    int i=l-1, j=r+1;
    while(i < j){
        do i++; while(a[i] < pivot);
        do j--; while(a[j] > pivot);
        if(i < j) swap(a[i], a[j]);
    }
    int leftCnt = j - l + 1;
    if(k <= leftCnt) return quickSelect(l, j, k);
    else return quickSelect(j+1, r, k-leftCnt);
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(0);
    int n, k;
    cin >> n >> k;
    for(int i=0; i<n; i++) cin >> a[i];
    cout << quickSelect(0, n-1, k) << endl;
    return 0;
}

