LinK33:
本题是找target在排序数组中的起止位置（lower_bound和upper_bound）。
用两次二分：第一次找第一个≥target的位置（左边界），第二次找最后一个≤target的位置（右边界）。
如果左边界指向的值≠target，说明没找到，输出-1 -1。
源码：
#include<iostream>
using namespace std;

int a[100005];

int lowerBound(int n, int target){
    int l=0, r=n-1, ans=-1;
    while(l <= r){
        int mid = l + (r-l)/2;
        if(a[mid] >= target){
            ans = mid;
            r = mid - 1;
        } else l = mid + 1;
    }
    return ans;
}

int upperBound(int n, int target){
    int l=0, r=n-1, ans=-1;
    while(l <= r){
        int mid = l + (r-l)/2;
        if(a[mid] <= target){
            ans = mid;
            l = mid + 1;
        } else r = mid - 1;
    }
    return ans;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(0);
    int n, q;
    cin >> n >> q;
    for(int i=0; i<n; i++) cin >> a[i];
    while(q--){
        int k;
        cin >> k;
        int left = lowerBound(n, k);
        if(left == -1 || a[left] != k)
            cout << "-1 -1" << endl;
        else {
            int right = upperBound(n, k);
            cout << left << " " << right << endl;
        }
    }
    return 0;
}

